descriptions = {
    467: ('A.b.p. Nocivelli SpA', 'Italian electrical installation services. High ROIC.', 'Italian electrical contractor.', "Nocivelli is an Italian company providing electrical installation, automation, and energy efficiency services for industrial and commercial customers. The company benefits from growing demand for industrial automation and energy-efficient electrical systems across Italy and Europe.", 'Electrical services. High ROIC compounder.', 'Italian electrical compounder.', "An Italian electrical installation and automation company with a 53.4% ROIC and EPS growth of 8.7% annualised. Nocivelli provides electrical systems and energy efficiency solutions for Italian industrial and commercial customers — benefiting from structural electrification and automation investment.", ["Electrical installation, automation and energy efficiency services for industry and commerce.", "ROIC of 53.4% — exceptional returns from a capital-light electrical services model.", "EPS grew 8.7% annualised with consistent demand from industrial electrification investment.", "Revenue grew 14.7% annualised as industrial automation and energy efficiency spending expanded."]),
    468: ('Altria Group Inc', 'US tobacco giant. Exceptional yield.', 'US tobacco income.', "Altria is the dominant US tobacco company, owning the Marlboro brand — the best-selling cigarette in the United States. The company generates extraordinary free cash flow from its tobacco franchise and returns virtually all of it to shareholders through dividends and buybacks.", 'Marlboro dominance. Exceptional yield.', 'US tobacco income machine.', "The owner of the Marlboro brand with a 29.7% ROIC and EPS growth of 11.4% annualised. Altria generates extraordinary free cash flow from its dominant US tobacco position and returns virtually all of it to shareholders. The stock trades at a low multiple reflecting regulatory risk — but the cash generation is real.", ["Owner of the Marlboro brand — the best-selling cigarette in the United States.", "ROIC of 29.7% reflects extraordinary pricing power and brand loyalty in tobacco.", "EPS grew 11.4% annualised with consistent price increases offsetting volume declines.", "Virtually all free cash flow returned to shareholders through dividends and buybacks."]),
    469: ('Alvopetro Energy Ltd', 'Canadian natural gas producer in Brazil. High growth.', 'Brazil natural gas producer.', "Alvopetro Energy is a Canadian company producing natural gas and condensate in the Reconcavo Basin of Brazil. The company sells gas directly to industrial customers in Bahia under long-term contracts — a captive customer base with predictable, dollar-linked revenues.", 'Brazil gas. High growth momentum.', 'Brazilian energy compounder.', "A Canadian natural gas producer in Brazil with a 28.3% ROIC and EPS growth of 29.5% annualised. Alvopetro produces gas in the Reconcavo Basin and sells directly to Brazilian industrial customers under long-term dollar-linked contracts — a highly profitable, predictable business.", ["Natural gas and condensate production in the Reconcavo Basin, Bahia, Brazil.", "Direct sales to industrial customers under long-term dollar-linked contracts.", "ROIC of 28.3% reflects high-margin gas production with captive industrial customers.", "EPS grew 29.5% annualised as production volumes and gas prices expanded."]),
    470: ('Applied Industrial Technologies', 'US industrial distribution. High ROIC compounder.', 'Industrial distribution compounder.', "Applied Industrial Technologies is a US distributor of bearings, power transmission, fluid power, and industrial automation components. The company serves manufacturing, energy, and food processing customers with mission-critical MRO parts and technical services.", 'Industrial MRO distribution. High ROIC.', 'US industrial compounder.', "A US industrial components distributor with a 17.5% ROIC and EPS growth of 23.3% annualised. Applied Industrial distributes bearings, power transmission, and fluid power components to manufacturers — mission-critical MRO parts that keep production lines running, creating recurring demand.", ["Bearings, power transmission, fluid power and automation components for industry.", "ROIC of 17.5% reflects consistent returns from mission-critical MRO distribution.", "EPS grew 23.3% annualised with consistent demand from manufacturing and energy customers.", "Revenue grew 6.1% annualised with organic growth and technical service expansion."]),
    471: ('AQ Group', 'Swedish electronics manufacturer. Quality compounder.', 'Swedish electronics manufacturer.', "AQ Group is a Swedish contract manufacturer of electrical components, cables, and metal structures for the automotive, industrial, and infrastructure sectors. The company operates factories across Europe, Asia, and the Americas — serving blue-chip industrial customers with customised manufactured components.", 'Swedish contract manufacturing. Quality compounder.', 'Nordic electronics compounder.', "A Swedish electronics contract manufacturer with a 14.1% ROIC and EPS growth of 16.4% annualised. AQ Group produces cables, electrical components, and metal structures for automotive and industrial customers across global manufacturing facilities.", ["Electrical components, cables and metal structures for automotive and industrial customers.", "ROIC of 14.1% reflects consistent returns from global contract manufacturing operations.", "EPS grew 16.4% annualised with consistent demand from blue-chip industrial customers.", "Revenue grew 6.0% annualised with expansion across European and Asian manufacturing."]),
    472: ('Ardmore Shipping Corp', 'Marshall Islands product and chemical tanker. High ROIC.', 'Product and chemical tanker.', "Ardmore Shipping operates a fleet of product and chemical tankers serving global refined petroleum and chemical trade routes. The company benefits from strong demand for product tanker shipping as refinery capacity shifts geographically and chemical trade volumes grow.", 'Product tankers. High ROIC income.', 'Chemical tanker income.', "A Marshall Islands product and chemical tanker operator with a 12.3% ROIC and EPS growth of 47.3% annualised. Ardmore fleet serves global refined products and chemical trade — benefiting from geographic refinery shifts that lengthen average voyage distances.", ["Product and chemical tanker fleet serving global refined petroleum and chemical trade.", "ROIC of 12.3% reflects strong tanker market conditions and fleet efficiency.", "EPS grew 47.3% annualised as product tanker rates and utilisation remained elevated.", "Geographic refinery capacity shifts structurally lengthening average voyage distances."]),
    473: ('Bains de Mer Monaco', 'Monaco casino and resort operator. Exceptional niche.', 'Monaco casino monopoly.', "Societe des Bains de Mer operates the Casino de Monte-Carlo and luxury hotel and resort assets in Monaco. The company holds a concession to operate Monaco's iconic casino — one of the most famous gambling destinations in the world — alongside luxury hotels, restaurants, and spa facilities.", 'Monaco casino monopoly. Exceptional niche.', 'Monaco luxury monopoly.', "The operator of Casino de Monte-Carlo with a 19.9% ROIC and EPS growth of 28.3% annualised. Bains de Mer holds Monaco's casino concession — effectively a monopoly on one of the world's most famous gambling destinations, surrounded by luxury hotel and restaurant assets.", ["Operator of Casino de Monte-Carlo — Monaco's iconic luxury gambling destination.", "ROIC of 19.9% reflects strong margins from the luxury casino and resort concession.", "EPS grew 28.3% annualised as Monaco luxury tourism and gaming revenues recovered.", "Monopoly concession on Monaco casino with luxury hotels and restaurants alongside."]),
    474: ('Bic', 'French consumer goods. Magic formula value.', 'Iconic consumer brand value.', "BIC is a French consumer goods company producing disposable pens, lighters, and shavers sold in over 160 countries. Trading at an attractive Magic Formula valuation — high earnings yield combined with strong return on capital — BIC represents a quality consumer brand at a discounted price.", 'Iconic brand. Magic formula value.', 'Consumer brand value play.', "A globally recognised French consumer goods brand with a 14.1% ROIC trading at an attractive Magic Formula valuation. BIC disposable products generate high-frequency recurring demand across 160+ countries — a quality business available at a discounted price relative to its earnings power.", ["Disposable pens, lighters and shavers sold in 160+ countries — recurring consumable demand.", "ROIC of 14.1% reflects consistent returns from a mature, cash-generative brand business.", "Magic Formula screen identifies high earnings yield combined with quality ROIC.", "Trading below intrinsic value as the market undervalues the franchise's durability."]),
    475: ('Boston Pizza Royalties Income', 'Canadian pizza royalty. Magic formula value.', 'Pizza royalty value.', "Boston Pizza Royalties Income Fund collects royalties on all Boston Pizza restaurant sales across Canada. The fund screens strongly on the Magic Formula — combining a high earnings yield with a solid return on capital from a pure royalty business model.", 'Pizza royalty. Magic formula value.', 'Royalty income value play.', "A Canadian pizza royalty trust with a 9.5% ROIC screening strongly on the Magic Formula. The fund earns royalties on all Boston Pizza Canada system sales with minimal capital requirements — a high earnings yield business with consistent cash generation.", ["Pure royalty trust on Boston Pizza Canada system sales — zero restaurant operating risk.", "ROIC of 9.5% from a capital-light royalty and brand ownership model.", "EPS grew 35.1% annualised as post-COVID dining recovery boosted system sales.", "High earnings yield combined with quality ROIC — classic Magic Formula screen."]),
    476: ('Brady Corp', 'US identification and safety products. Quality compounder.', 'Safety identification products.', "Brady Corporation is a US manufacturer of identification solutions — labels, signs, printers, and safety products used in workplaces, electrical systems, and industrial facilities globally. The company products help customers comply with safety regulations and manage assets efficiently.", 'Safety identification. Quality compounder.', 'Industrial safety compounder.', "A US workplace identification and safety products manufacturer with a 16.6% ROIC and EPS growth of 11.6% annualised. Brady produces labels, signs, and printers for workplace safety compliance and asset management — a recurring consumable business with consistent regulatory demand.", ["Identification labels, safety signs and industrial printers for workplace compliance.", "ROIC of 16.6% reflects consistent returns from regulatory-driven safety product demand.", "EPS grew 11.6% annualised with consistent demand from industrial safety requirements.", "Revenue grew 10.5% annualised as workplace safety regulation and asset management demand grew."]),
    477: ('Cactus Inc', 'US wellhead equipment manufacturer. Quality niche.', 'Wellhead equipment specialist.', "Cactus is a US manufacturer of wellheads and pressure control equipment for oil and gas production. The company products are safety-critical components at the surface of every well — controlling pressure and flow during drilling and production operations.", 'Wellhead equipment. Quality niche.', 'Wellhead technology compounder.', "A US wellhead and pressure control equipment manufacturer with a 13.0% ROIC and EPS growth of 27.1% annualised. Cactus produces safety-critical wellhead systems for US oil and gas producers — equipment specified into every well drilled, with recurring demand from active drilling programmes.", ["Wellheads and pressure control equipment — safety-critical surface components for oil and gas wells.", "ROIC of 13.0% reflects consistent returns from essential well safety equipment.", "EPS grew 27.1% annualised as US drilling activity and wellhead demand expanded.", "Recurring demand from active drilling programmes across US shale basins."]),
    478: ('Cairn Homes PLC', 'Irish homebuilder. Structural housing demand.', 'Irish homebuilder.', "Cairn Homes is Ireland's largest homebuilder, constructing homes across Dublin and the greater Leinster region. Ireland has one of the most severe housing shortages in Europe — demand for new homes significantly exceeds supply, providing multi-year structural tailwinds for quality builders.", 'Irish housing shortage. Quality builder.', 'Irish homebuilder compounder.', "Ireland's largest homebuilder with a 9.1% ROIC and EPS growth of 65.8% annualised, benefiting from one of Europe's most severe housing shortages. Cairn Homes builds in Dublin and Leinster — the most undersupplied housing markets in Ireland.", ["Ireland's largest homebuilder operating in Dublin and Leinster region.", "One of Europe's most severe housing shortages provides multi-year demand tailwind.", "EPS grew 65.8% annualised as housing delivery and selling prices expanded strongly.", "Revenue grew 9.9% annualised with consistent housing completions across Dublin markets."]),
    479: ('Cardinal Energy Ltd', 'Canadian oil producer. High yield income.', 'Canadian oil income producer.', "Cardinal Energy is a Canadian oil producer focused on low-decline, conventional oil production in Alberta and Saskatchewan. The company operates mature oil fields with predictable production profiles — generating stable free cash flow to support a high dividend yield.", 'Low-decline oil. High yield income.', 'Canadian oil income play.', "A Canadian conventional oil producer with a 16.5% ROIC and a high dividend yield from low-decline Alberta and Saskatchewan oil production. Cardinal Energy stable, predictable production profile generates consistent free cash flow to support its income-focused shareholder return strategy.", ["Low-decline conventional oil production in Alberta and Saskatchewan.", "ROIC of 16.5% reflects consistent returns from mature, predictable oil producing assets.", "EPS grew 15.3% annualised as production and oil prices remained supportive.", "High dividend yield supported by stable free cash flow from low-decline production."]),
    480: ('Cembre SpA', 'Italian electrical connectors. Magic formula value.', 'Electrical connector value play.', "Cembre is an Italian manufacturer of safety-critical electrical connectors for utilities, railways, and industrial customers. The company screens strongly on the Magic Formula — combining high ROIC with an attractive earnings yield, reflecting quality at a reasonable price.", 'Quality connectors. Magic formula value.', 'Connector value compounder.', "An Italian electrical connector manufacturer with a 19.9% ROIC screening strongly on the Magic Formula. Cembre safety-critical connectors serve utilities and railways with high switching costs and long customer relationships — quality business at an attractive earnings yield.", ["Safety-critical electrical connectors for utilities, railways and industrial applications.", "ROIC of 19.9% combined with attractive earnings yield — classic Magic Formula screen.", "EPS grew 19.6% annualised driven by European grid and railway infrastructure investment.", "High switching costs from safety certification requirements create durable customer relationships."]),
    481: ('Clarkson PLC', 'Leading global shipbroker. Magic formula value.', 'Shipbroking value play.', "Clarkson is the world's largest shipbroking firm, acting as intermediary in the buying, selling, and chartering of ships globally. The company screens on the Magic Formula — combining an exceptional ROIC with an attractive earnings yield in a capital-light advisory business.", 'Shipbroking leader. Magic formula value.', 'Shipbroking value compounder.', "The world's largest shipbroker with an 89.5% ROIC screening strongly on the Magic Formula. Clarkson advisory model requires minimal capital yet sits at the centre of global shipping transactions — quality business available at a compelling earnings yield.", ["World's largest shipbroking firm — intermediary in global ship chartering and sale.", "ROIC of 89.5% — extraordinary returns from a capital-light advisory business.", "EPS grew 33.5% annualised driven by elevated shipping market activity.", "High earnings yield combined with exceptional ROIC — Magic Formula screen highlight."]),
    482: ('Coca-Cola Consolidated Inc', 'US Coca-Cola bottler. High ROIC compounder.', 'US Coca-Cola bottler.', "Coca-Cola Consolidated is the largest US Coca-Cola bottler, distributing Coke products across 14 states in the Southeast, Midwest, and Mid-Atlantic regions. The company benefits from the iconic Coca-Cola brand, exclusive territorial rights, and growing premium beverage demand.", 'Largest US Coke bottler. High ROIC.', 'Coca-Cola bottler compounder.', "The largest US Coca-Cola bottler with a 16.9% ROIC and EPS growth of 30.0% annualised. Coca-Cola Consolidated holds exclusive distribution rights across 14 US states — a franchised territory model generating consistent cash flow from the world's most recognised beverage brand.", ["Largest US Coca-Cola bottler — exclusive distribution rights across 14 US states.", "ROIC of 16.9% reflects consistent returns from franchised Coca-Cola territory rights.", "EPS grew 30.0% annualised with pricing power and premium beverage mix improvements.", "Revenue grew 4.8% annualised with consistent volume growth from Coke brand strength."]),
    483: ('COSCO SHIPPING Holdings Co Ltd', 'Chinese container shipping giant. High ROIC.', 'China container shipping leader.', "COSCO SHIPPING Holdings is one of the world's largest container shipping companies, operating a massive fleet of container vessels under the COSCO and OOCL brands. The company is state-owned and benefits from China's dominant role in global trade and manufacturing exports.", 'Chinese container shipping. High ROIC.', 'China shipping compounder.', "One of the world's largest container shipping companies with a 47.7% ROIC and EPS growth of 38.4% annualised. COSCO SHIPPING operates COSCO and OOCL container brands globally — benefiting from China's central role in global manufacturing and export trade.", ["One of the world's largest container fleets under COSCO and OOCL brands.", "ROIC of 47.7% reflects extraordinary returns during elevated container shipping rate period.", "EPS grew 38.4% annualised as container demand and freight rates remained structurally elevated.", "Revenue grew 30.8% annualised driven by surging global container shipping volumes."]),
    484: ('Cosmo Pharmaceuticals NV', 'Italian specialty pharma. Quality compounder.', 'GI specialty pharma.', "Cosmo Pharmaceuticals is an Italian specialty pharmaceutical company focused on gastrointestinal drugs. The company develops and commercialises treatments for inflammatory bowel disease and colorectal cancer detection — niche therapeutic areas with high unmet medical need.", 'GI pharma specialist. Quality compounder.', 'Specialty GI pharma.', "An Italian gastrointestinal specialty pharmaceutical company with a 10.0% ROIC focused on inflammatory bowel disease and colorectal cancer detection. Cosmo develops niche GI drugs with high clinical value — therapeutic areas with significant unmet need and growing patient populations.", ["Specialty gastrointestinal drugs for inflammatory bowel disease and colorectal cancer.", "Niche GI therapeutic areas with high unmet medical need and growing patient populations.", "ROIC of 10.0% with improving trajectory from specialty drug pipeline commercialisation.", "EPS growing as specialty GI drug portfolio gains market share in European markets."]),
    485: ('dAmico International Shipping SA', 'Italian product tanker operator. High earnings growth.', 'Product tanker specialist.', "dAmico International Shipping is an Italian operator of product tankers transporting refined petroleum products globally. The company operates a modern fleet of MR and LR product tankers serving the world's major refinery-to-consumer trade routes.", 'Product tankers. Strong earnings growth.', 'Product tanker income.', "An Italian product tanker operator with a 14.2% ROIC and EPS growth of 41.7% annualised. dAmico fleet of MR and LR tankers transports refined petroleum products globally — benefiting from geographic shifts in refinery capacity that lengthen tanker voyage distances.", ["MR and LR product tanker fleet serving global refined petroleum trade routes.", "ROIC of 14.2% reflects strong product tanker market conditions and fleet efficiency.", "EPS grew 41.7% annualised as product tanker rates remained structurally elevated.", "Geographic refinery capacity shifts driving longer average voyage distances."]),
    486: ('EBARA JITSUGYO Co Ltd', 'Japanese pump distributor. Magic formula value.', 'Industrial pump value play.', "Ebara Jitsugyo is a Japanese distributor and manufacturer of industrial pumps for chemical, pharmaceutical, and semiconductor industries. The company screens on the Magic Formula — combining a high ROIC with an attractive earnings yield in a specialised pump distribution business.", 'Industrial pumps. Magic formula value.', 'Japanese pump value compounder.', "A Japanese industrial pump specialist with a 33.3% ROIC screening on the Magic Formula. Ebara Jitsugyo fluid handling equipment serves semiconductor fabs and chemical plants — quality business with high switching costs available at an attractive earnings yield.", ["Industrial pump and fluid handling equipment for semiconductor, chemical and pharmaceutical.", "ROIC of 33.3% combined with attractive earnings yield — Magic Formula screen highlight.", "EPS grew 14.8% annualised with consistent semiconductor manufacturing demand.", "High switching costs from mission-critical pump applications create durable relationships."]),
    487: ('Ernst Russ AG', 'German shipping asset manager. High ROIC.', 'Shipping asset manager.', "Ernst Russ is a German shipping company and asset manager specialising in container and bulk carrier vessel management. The company manages a fleet of ships for third-party owners and invests in shipping assets — benefiting from elevated freight rates and vessel values.", 'Shipping asset management. High ROIC.', 'Shipping asset compounder.', "A German shipping asset manager with a 22.5% ROIC and EPS growth of 80.5% annualised. Ernst Russ manages container and bulk carrier vessels for third-party owners — an asset-light management model generating fee income alongside proprietary shipping investments.", ["Container and bulk carrier vessel management for third-party shipping asset owners.", "ROIC of 22.5% reflects strong returns from shipping asset management and investments.", "EPS grew 80.5% annualised as vessel values and freight rates supported asset returns.", "Asset-light management model generates fee income with minimal capital requirements."]),
    488: ('EUROKAI GmbH & Co KGaA', 'German container terminal. Magic formula value.', 'Container terminal value play.', "Eurokai is a German container terminal operator at Hamburg and Trieste. The company screens on the Magic Formula — port terminal infrastructure with a consistent ROIC at an attractive earnings yield. Port concessions are long-life assets with extremely high barriers to entry.", 'Container terminal. Magic formula value.', 'Port infrastructure value.', "A German container terminal operator with an 11.8% ROIC screening on the Magic Formula. Eurokai Hamburg and Trieste terminals generate consistent infrastructure returns from a port concession that cannot be replicated — quality infrastructure at an attractive earnings yield.", ["Container terminal operator at Hamburg and Trieste — strategic European port locations.", "ROIC of 11.8% from long-life port concession assets with very high barriers to entry.", "EPS grew 27.5% annualised as container volumes and terminal revenues recovered.", "Magic Formula screen identifies quality port infrastructure at attractive earnings yield."]),
    489: ('Euroseas Ltd', 'Greek container shipping. Exceptional ROIC.', 'Container shipping compounder.', "Euroseas operates a fleet of feeder and intermediate container vessels serving inter-regional trade lanes globally. The company has generated exceptional returns during the container shipping boom and maintains a strong balance sheet.", 'Container shipping. Exceptional ROIC.', 'Container shipping value.', "A Greek container shipping company with a 31.5% ROIC and EPS growth of 97.4% annualised. Euroseas feeder and intermediate container fleet serves regional trade lanes globally — generating exceptional cash returns during elevated freight rate environments.", ["Feeder and intermediate container vessels serving inter-regional global trade lanes.", "ROIC of 31.5% — strong returns from elevated container shipping market conditions.", "EPS grew 97.4% annualised as container freight rates remained structurally elevated.", "Strong balance sheet and low valuation relative to net asset value of the fleet."]),
    490: ('Evertz Technologies Ltd', 'Canadian broadcast technology. Magic formula value.', 'Broadcast technology value.', "Evertz Technologies manufactures broadcast infrastructure equipment for television studios and streaming facilities worldwide. The company screens on the Magic Formula — combining high ROIC from a technology leadership position with an attractive earnings yield.", 'Broadcast tech. Magic formula value.', 'Broadcast technology value play.', "A Canadian broadcast technology company with a 32.2% ROIC screening on the Magic Formula. Evertz routing and monitoring systems are embedded in virtually every major broadcaster globally — quality technology business available at an attractive earnings yield.", ["Broadcast infrastructure equipment for TV studios and streaming facilities globally.", "ROIC of 32.2% combined with attractive earnings yield — Magic Formula screen highlight.", "EPS grew 8.3% annualised with consistent demand from broadcaster infrastructure upgrades.", "Market leadership in broadcast routing creates high switching costs and recurring revenue."]),
    491: ('Exxaro Resources Ltd', 'South African coal producer. Magic formula value.', 'South African coal value.', "Exxaro Resources is one of South Africa's largest coal producers, supplying Eskom's power stations and exporting thermal coal. The company screens on the Magic Formula — combining a solid ROIC with a high earnings yield reflecting the market's discounting of coal's long-term outlook.", 'South African coal. Magic formula value.', 'Coal income value play.', "A South African coal producer with a 16.3% ROIC screening on the Magic Formula. Exxaro supplies Eskom with thermal coal for domestic power generation — captive demand providing earnings visibility despite market concerns about the long-term coal outlook.", ["South Africa's largest coal supplier to Eskom — captive domestic power generation demand.", "ROIC of 16.3% combined with high earnings yield — Magic Formula screen highlight.", "EPS grew 2.4% annualised with stable domestic coal demand from power generation.", "High dividend yield reflects generous cash return policy from strong free cash flow."]),
    492: ('Faes Farma SA', 'Spanish specialty pharma. High revenue growth.', 'Spanish specialty pharma.', "Faes Farma is a Spanish pharmaceutical company specialising in bilastine — a second-generation antihistamine — and animal health products. The company has successfully internationalised its flagship bilastine product, achieving significant market penetration across Europe and Latin America.", 'Specialty antihistamine. High growth.', 'Spanish pharma compounder.', "A Spanish specialty pharmaceutical company with a 14.3% ROIC and revenue growth of 23.7% annualised. Faes Farma bilastine antihistamine has achieved strong international market penetration — a proprietary drug with growing global prescriptions and consistent earnings expansion.", ["Bilastine antihistamine and animal health products — internationalised specialty pharma.", "ROIC of 14.3% reflects consistent returns from proprietary drug commercialisation.", "Revenue grew 23.7% annualised as bilastine achieved strong international market penetration.", "EPS grew 0.8% annualised as investment in international expansion continued."]),
    493: ('Freehold Royalties Ltd', 'Canadian oil royalty income. High yield.', 'Canadian oil royalty.', "Freehold Royalties is a Canadian company that owns royalty interests in oil and gas producing lands across Western Canada and the US. The company earns royalties on production from its lands without bearing any operating costs — a pure royalty model with high margins and minimal capital requirements.", 'Canadian oil royalties. High yield.', 'Oil royalty income.', "A Canadian oil royalty company with an 11.4% ROIC and a high dividend yield from royalty interests across Western Canada and the US. Freehold earns production royalties without operating costs — an exceptionally efficient income model with consistent cash flow from diversified royalty lands.", ["Royalty interests on oil and gas producing lands across Western Canada and the US.", "ROIC of 11.4% from a pure royalty model with zero operating cost exposure.", "EPS grew 46.1% annualised as production volumes and oil prices improved.", "High dividend yield backed by consistent royalty income from diversified producing lands."]),
    494: ('G. Willi-Food International Ltd', 'Israeli kosher food distributor. Quality niche.', 'Israeli kosher food.', "G. Willi-Food is an Israeli importer and distributor of kosher food products across Israel and internationally. The company sources food products globally and distributes through Israeli retail, foodservice, and export channels — serving a structurally stable kosher food market.", 'Kosher food distribution. Quality niche.', 'Israeli food compounder.', "An Israeli kosher food distributor with a 16.9% ROIC and EPS growth of 10.8% annualised. G. Willi-Food sources and distributes kosher food products across Israel and export markets — a niche with consistent consumer demand and strong retail relationships.", ["Kosher food importing and distribution across Israeli retail and foodservice channels.", "ROIC of 16.9% reflects consistent returns from a niche kosher food distribution business.", "EPS grew 10.8% annualised with stable demand from the kosher food consumer market.", "Revenue grew 6.0% annualised with consistent domestic and export channel expansion."]),
    495: ('Games Workshop Group PLC', 'UK Warhammer creator. Magic formula value.', 'Warhammer IP value play.', "Games Workshop creates and sells Warhammer tabletop miniatures globally. The company screens strongly on the Magic Formula — combining one of the highest ROICs in UK equity markets with an attractive earnings yield, reflecting a quality IP business at a reasonable price.", 'Warhammer monopoly. Magic formula value.', 'IP monopoly value play.', "The creator of Warhammer with an 85.7% ROIC screening strongly on the Magic Formula. Games Workshop owns the entire Warhammer value chain from IP through manufacturing and retail — extraordinary returns available at an attractive earnings yield.", ["Creator of the Warhammer franchise — globally recognised tabletop miniatures IP.", "ROIC of 85.7% — one of the highest in UK equity markets from vertically integrated IP.", "EPS grew 10.9% annualised with consistent global expansion of the Warhammer universe.", "Magic Formula screen identifies exceptional ROIC at an attractive earnings yield."]),
    496: ('Garmin Ltd', 'US GPS technology leader. Magic formula value.', 'GPS technology value play.', "Garmin is a US GPS and navigation technology company operating across aviation, marine, outdoor, and fitness markets. The company screens on the Magic Formula — combining a high ROIC from technology leadership with an attractive earnings yield.", 'GPS technology. Magic formula value.', 'Navigation technology value play.', "A US GPS and navigation technology company with a 23.5% ROIC screening on the Magic Formula. Garmin has diversified across aviation, marine, outdoor, and fitness — multiple high-margin verticals generating consistent earnings growth available at an attractive valuation.", ["GPS navigation and wearable technology across aviation, marine, outdoor and fitness.", "ROIC of 23.5% combined with attractive earnings yield — Magic Formula screen highlight.", "EPS grew 10.8% annualised with consistent growth from aviation and wearables segments.", "Revenue grew 15.1% annualised as smartwatch and aviation growth accelerated."]),
}

with open(CARDS_PATH, 'r', encoding='utf-8') as f:
    content = f.read()

updated = 0
for card_id, (company, tag, tagBold, tagFull, pick, pickBold, pickFull, bullets) in descriptions.items():
    pattern = re.compile(
        rf"(id: {card_id}, type: 'QUEEN'.*?tag: ')[^']*('.*?tagBold: ')[^']*('.*?tagFull: \")[^\"]*(\",.*?pick: ')[^']*('.*?pickBold: ')[^']*('.*?pickFull: \")[^\"]*(\",)",
        re.DOTALL
    )
    replacement = rf"\g<1>{tag}\g<2>{tagBold}\g<3>{tagFull}\g<4>{pick}\g<5>{pickBold}\g<6>{pickFull}\g<7>"
    new_content = pattern.sub(replacement, content)
    if new_content != content:
        content = new_content
        updated += 1
        print(f"✅ {card_id}: {company}")
    else:
        print(f"❌ {card_id}: pattern not matched")
    bullets_str = ', '.join([f'"{b}"' for b in bullets])
    bullets_pattern = re.compile(rf"(id: {card_id},.*?bullets: \[)[^\]]*\]", re.DOTALL)
    content = bullets_pattern.sub(rf"\g<1>{bullets_str}]", content)

with open(CARDS_PATH, 'w', encoding='utf-8') as f:
    f.write(content)

print(f"\n✅ Updated {updated}/30 QUEEN cards")
print(f"Remaining generic: {content.count('operates in')}")
